pragma solidity ^0.8.9;

import "@openzeppelin/contracts/security/ReentrancyGuard.sol";
import "@openzeppelin/contracts/token/ERC721/extensions/ERC721URIStorage.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/cryptography/MerkleProof.sol";

contract MyNFTCollection is ERC721URIStorage, Ownable, ReentrancyGuard {
    using MerkleProof for bytes32[];

    uint256 public constant MAX_SUPPLY = 10000;
    uint256 public constant PRICE = 0.01 ether;
    uint256 public constant MAX_PER_MINT = 10;
    bool public isActive = false;
    string private baseTokenURI;
    address payable public beneficiary;
    uint256 public royaltyPercentage;
    uint256 public maxPerUser = 10;
    bytes32 public rootHash;

    mapping(address => uint256) private mintedPerAddress;
    uint256 private totalSupplyCounter;

    event Mint(address indexed minter, uint256 tokenId);
    event RoyaltyPaid(uint256 amount);

    constructor(string memory _baseTokenURI, address payable _beneficiary, uint256 _royaltyPercentage, bytes32 _rootHash) ERC721("MyNFT", "MNFT") {
        baseTokenURI = _baseTokenURI;
        beneficiary = _beneficiary;
        royaltyPercentage = _royaltyPercentage;
        rootHash = _rootHash;
    }

    modifier whenMintingActive() {
        require(isActive, "Minting is not active");
        _;
    }

    function activateMinting() external onlyOwner {
        isActive = true;
    }

    function deactivateMinting() external onlyOwner {
        isActive = false;
    }

    function mintNFTs(bytes32[] calldata merkleProof) external payable whenMintingActive nonReentrant {
        require(isActive, "Minting is not active");
        require(msg.value >= PRICE * MAX_PER_MINT, "Insufficient funds");
        require(mintedPerAddress[msg.sender] + MAX_PER_MINT <= maxPerUser, "Exceeds max per user");

        bytes32 leaf = keccak256(abi.encodePacked(msg.sender));
        require(MerkleProof.verify(merkleProof, rootHash, leaf), "Invalid proof");

        uint256 totalSupply = totalSupplyCounter;
        require(totalSupply + MAX_PER_MINT <= MAX_SUPPLY, "Exceeds max supply");

        for (uint256 i = 0; i < MAX_PER_MINT; i++) {
            _safeMint(msg.sender, totalSupply + i);
            emit Mint(msg.sender, totalSupply + i);
        }

        mintedPerAddress[msg.sender] += MAX_PER_MINT;
        totalSupplyCounter += MAX_PER_MINT;
    }

    function reserveNFTs(address recipient, uint256 quantity) external onlyOwner {
        require(quantity > 0, "Quantity must be greater than zero");
        require(totalSupplyCounter + quantity <= MAX_SUPPLY, "Exceeds max supply");

        for (uint256 i = 0; i < quantity; i++) {
            _safeMint(recipient, totalSupplyCounter + i);
        }
        totalSupplyCounter += quantity;
    }

    function setBaseURI(string memory _baseTokenURI) external onlyOwner {
        baseTokenURI = _baseTokenURI;
    }

    function tokenURI(uint256 tokenId) public view override returns (string memory) {
        require(_exists(tokenId), "Token does not exist");
        return string(abi.encodePacked(baseTokenURI, "/", tokenId.toString(), ".json"));
    }

    function setRoyalties(uint256 _royaltyPercentage) external onlyOwner {
        require(_royaltyPercentage <= 10000, "Royalty percentage exceeds 100%");
        royaltyPercentage = _royaltyPercentage;
    }

    function withdraw() external onlyOwner {
        uint256 balance = address(this).balance;
        uint256 royaltyAmount = (balance * royaltyPercentage) / 10000;
        uint256 transferAmount = balance - royaltyAmount;

        (bool success, ) = beneficiary.call{value: transferAmount}("");
        require(success, "Transfer failed");

        emit RoyaltyPaid(royaltyAmount);
    }

    function verifyMerkleProof(bytes32[] calldata proof, bytes32 leaf) public view returns (bool) {
        return MerkleProof.verify(proof, rootHash, leaf);
    }
}
